  1→package pub.hackers.android.ui.screens.auth
  2→
  3→import androidx.lifecycle.ViewModel
  4→import androidx.lifecycle.viewModelScope
  5→import dagger.hilt.android.lifecycle.HiltViewModel
  6→import kotlinx.coroutines.flow.MutableStateFlow
  7→import kotlinx.coroutines.flow.StateFlow
  8→import kotlinx.coroutines.flow.asStateFlow
  9→import kotlinx.coroutines.flow.update
 10→import kotlinx.coroutines.launch
 11→import pub.hackers.android.data.local.SessionManager
 12→import pub.hackers.android.data.repository.HackersPubRepository
 13→import javax.inject.Inject
 14→
 15→enum class SignInStep {
 16→    USERNAME,
 17→    VERIFICATION
 18→}
 19→
 20→data class SignInUiState(
 21→    val step: SignInStep = SignInStep.USERNAME,
 22→    val username: String = "",
 23→    val code: String = "",
 24→    val challengeToken: String? = null,
 25→    val isLoading: Boolean = false,
 26→    val isSignedIn: Boolean = false,
 27→    val error: String? = null
 28→)
 29→
 30→@HiltViewModel
 31→class SignInViewModel @Inject constructor(
 32→    private val repository: HackersPubRepository,
 33→    private val sessionManager: SessionManager
 34→) : ViewModel() {
 35→
 36→    private val _uiState = MutableStateFlow(SignInUiState())
 37→    val uiState: StateFlow<SignInUiState> = _uiState.asStateFlow()
 38→
 39→    fun updateUsername(username: String) {
 40→        _uiState.update { it.copy(username = username) }
 41→    }
 42→
 43→    fun updateCode(code: String) {
 44→        _uiState.update { it.copy(code = code) }
 45→    }
 46→
 47→    fun sendVerificationCode() {
 48→        val username = _uiState.value.username.trim()
 49→        if (username.isEmpty()) return
 50→
 51→        viewModelScope.launch {
 52→            _uiState.update { it.copy(isLoading = true, error = null) }
 53→
 54→            repository.loginByUsername(username)
 55→                .onSuccess { challenge ->
 56→                    _uiState.update {
 57→                        it.copy(
 58→                            step = SignInStep.VERIFICATION,
 59→                            challengeToken = challenge.token,
 60→                            isLoading = false
 61→                        )
 62→                    }
 63→                }
 64→                .onFailure { error ->
 65→                    _uiState.update {
 66→                        it.copy(
 67→                            error = error.message,
 68→                            isLoading = false
 69→                        )
 70→                    }
 71→                }
 72→        }
 73→    }
 74→
 75→    fun verifyCode() {
 76→        val token = _uiState.value.challengeToken ?: return
 77→        val code = _uiState.value.code.trim()
 78→        if (code.isEmpty()) return
 79→
 80→        viewModelScope.launch {
 81→            _uiState.update { it.copy(isLoading = true, error = null) }
 82→
 83→            repository.completeLoginChallenge(token, code)
 84→                .onSuccess { session ->
 85→                    sessionManager.saveSession(
 86→                        token = session.id,
 87→                        userId = session.account.id,
 88→                        username = session.account.username,
 89→                        handle = session.account.handle,
 90→                        name = session.account.name,
 91→                        avatarUrl = session.account.avatarUrl
 92→                    )
 93→                    _uiState.update {
 94→                        it.copy(
 95→                            isLoading = false,
 96→                            isSignedIn = true
 97→                        )
 98→                    }
 99→                }
100→                .onFailure { error ->
101→                    _uiState.update {
102→                        it.copy(
103→                            error = error.message,
104→                            isLoading = false
105→                        )
106→                    }
107→                }
108→        }
109→    }
110→
111→    fun verifyWithDeepLink(token: String, code: String) {
112→        viewModelScope.launch {
113→            _uiState.update { it.copy(isLoading = true, error = null) }
114→
115→            repository.completeLoginChallenge(token, code)
116→                .onSuccess { session ->
117→                    sessionManager.saveSession(
118→                        token = session.id,
119→                        userId = session.account.id,
120→                        username = session.account.username,
121→                        handle = session.account.handle,
122→                        name = session.account.name,
123→                        avatarUrl = session.account.avatarUrl
124→                    )
125→                    _uiState.update {
126→                        it.copy(
127→                            isLoading = false,
128→                            isSignedIn = true
129→                        )
130→                    }
131→                }
132→                .onFailure { error ->
133→                    _uiState.update {
134→                        it.copy(
135→                            error = error.message,
136→                            isLoading = false
137→                        )
138→                    }
139→                }
140→        }
141→    }
142→
143→    fun goBackToUsername() {
144→        _uiState.update {
145→            it.copy(
146→                step = SignInStep.USERNAME,
147→                code = "",
148→                challengeToken = null
149→            )
150→        }
151→    }
152→
153→    fun clearError() {
154→        _uiState.update { it.copy(error = null) }
155→    }
156→}
